const requestType = $('Webhook').first().json.body.request_type;
const aiResponse = $('AI Agent').first().json.output;

// Obtener queryId del input anterior (MySQL Insert)
const mysqlResult = $input.first(); // Datos del MySQL Insert
const queryId = mysqlResult ? mysqlResult.json.insertId : null;

console.log('🔍 Request Type:', requestType);
console.log('🤖 AI Response:', aiResponse);
console.log('📊 Query ID:', queryId);

let processedResponse = {
  response_type: 'text',
  message: aiResponse,
  structured_data: null,
  sources: null,
  queryId: queryId
};

try {
  if (requestType === 'graph') {
    try {
      const parsedData = JSON.parse(aiResponse);
      if (parsedData.response_type === 'salary_data') {
        processedResponse = {
          response_type: 'salary_data',
          structured_data: parsedData,
          message: 'Datos de salarios generados correctamente',
          sources: parsedData.fuentes_utilizadas || [],
          queryId: queryId
        };
      }
    } catch (e) {
      console.log('❌ Error parsing graph data, usando como texto');
    }
  } else if (requestType === 'sources') {
    try {
      const parsedData = JSON.parse(aiResponse);
      if (parsedData.response_type === 'sources_info') {
        processedResponse = {
          response_type: 'sources_info',
          sources: parsedData.fuentes_utilizadas || [],
          message: parsedData.descripcion || 'Fuentes consultadas',
          structured_data: parsedData,
          queryId: queryId
        };
      }
    } catch (e) {
      console.log('❌ Error parsing sources data, usando como texto');
    }
  }
} catch (error) {
  console.log('❌ Error general:', error);
}

console.log('✅ Processed Response:', JSON.stringify(processedResponse, null, 2));

return [{
  json: processedResponse
}];

// Obtener datos del Switch/Edit Fields
const inputData = $input.first().json;

// Intentar obtener queryId de diferentes fuentes
let queryId = null;

// Opción 1: Buscar en nodos anteriores
try {
  queryId = $('MySQL1').first().json.insertId;
} catch (e) {
  console.log('No se pudo obtener queryId de MySQL1');
}

// Opción 2: Si viene del input
if (!queryId && inputData.queryId) {
  queryId = inputData.queryId;
}

// Construir respuesta final
const finalResponse = {
  success: true,
  response_type: inputData.response_type || "text",
  message: inputData.message || "",
  structured_data: inputData.structured_data || null,
  sources: inputData.sources || [],
  queryId: queryId,
  timestamp: new Date().toISOString()
};

console.log('🎯 Respuesta final Code3:', JSON.stringify(finalResponse, null, 2));

return {
  json: finalResponse
};

// Formatear historial para el prompt de la IA
const items = $input.all();
const webhook = $('Webhook').first().json.body;

let historialFormateado = "";

if (items && items.length > 0) {
  historialFormateado = "\n{HISTORIAL DE CONVERSACIÓN RECIENTE}\n";

  // Ordenar por fecha (más reciente primero) y tomar los últimos 5
  const conversaciones = items
    .filter(item => item.json.response_text) // Solo conversaciones completadas
    .slice(0, 5) // Últimas 5 conversaciones
    .reverse(); // Ordenar cronológicamente

  conversaciones.forEach((item, index) => {
    const fecha = new Date(item.json.created_at).toLocaleDateString('es-ES');
    historialFormateado += `\n--- Conversación ${index + 1} (${fecha}) ---\n`;
    historialFormateado += `Usuario: ${item.json.query_text}\n`;
    historialFormateado += `Asistente: ${item.json.response_text}\n`;
  });

  historialFormateado += "\n{FIN DEL HISTORIAL}\n";
} else {
  historialFormateado = "\n{HISTORIAL: Esta es la primera conversación del usuario}\n";
}

return [{
  json: {
    ...webhook,
    historial_formateado: historialFormateado,
    tiene_historial: items && items.length > 0
  }
}];

// Debug: Ver todos los datos que llegan
console.log('🔍 Input completo del Code1:', JSON.stringify($input.all(), null, 2));

// Obtener request_type del webhook
const webhookData = $('Webhook').first().json.body || {};
const requestType = webhookData.request_type || 'chat';

console.log('✅ request_type obtenido del webhook:', requestType);

const userMessage = webhookData.message || '';
const historial = $input.first().json.historial || '';

console.log('📋 Datos procesados:', {
  requestType: requestType,
  userMessage: userMessage.substring(0, 50) + '...',
  historial: historial.substring(0, 100) + '...'
});

let templateType = 'text';
let emptyTemplate = null;

// Si es solicitud de gráfica, SIEMPRE usar salary_data
if (requestType === 'graph') {
  console.log('🎯 Configurando para GRAPH - usando salary_data');
  templateType = 'salary_data';
  emptyTemplate = {
    "response_type": "salary_data",
    "sector": "",
    "data": {
      "salario_promedio": {
        "junior": {"min": 0, "max": 0, "promedio": 0, "moneda": "EUR"},
        "mid": {"min": 0, "max": 0, "promedio": 0, "moneda": "EUR"},
        "senior": {"min": 0, "max": 0, "promedio": 0, "moneda": "EUR"}
      },
      "tendencia_salarial": {
        "variacion_anual": "",
        "direccion": "",
        "factores_influencia": []
      },
      "datos_por_region": [],
      "habilidades_mejor_pagadas": []
    },
    "fecha_actualizacion": "2024-12-01",
    "fuentes_utilizadas": []
  };
} else if (requestType === 'sources') {
  console.log('🎯 Configurando para SOURCES');
  templateType = 'sources_info';
  emptyTemplate = {
    "response_type": "sources_info",
    "fuentes_utilizadas": []
  };
} else {
  console.log('🎯 Configurando para CHAT normal');
  templateType = 'text';
  emptyTemplate = null;
}

const result = {
  template_type: templateType,
  empty_template: emptyTemplate,
  original_request_type: requestType,
  historial: historial,
  message: userMessage,
  // Pasar todos los datos del webhook
  ...webhookData
};

console.log('🚀 Resultado final del Code1:', JSON.stringify(result, null, 2));

return {
  json: result
};
